{"path": "src/retry.js", "content": "const wait = (ms) => new Promise((r) => setTimeout(r, ms));

async function retry(fn, times = 3, delayMs = 200) {
  let lastErr;
  for (let i = 0; i < times; i++) {
    try {
      return await fn();
    } catch (e) {
      lastErr = e;
      await wait(delayMs * (i + 1));
    }
  }
  throw lastErr;
}

module.exports = { retry };
"}

