const { parentPort } = require('worker_threads');
const sharp = require('sharp');

parentPort.on('message', async ({ src, dst, width }) => {
  try {
    await sharp(src).resize(width).webp({ quality: 80 }).toFile(dst);
    parentPort.postMessage({ ok: true, dst });
  } catch (e) {
    parentPort.postMessage({ ok: false, error: e.message });
  }
});
